                                        <div className="w-24"></div>
                                    )}

                                    <input
                                      type="range"
                                      min={-48}
                                      max={6}
                                      step={1}
                                      value={volumes[trackIndex]}
                                      onChange={(e) => handleVolumeChange(trackIndex, parseInt(e.target.value))}
