import React, { useRef, useMemo } from 'react';
import * as THREE from 'three';
import { useFrame } from '@react-three/fiber';

interface NeonRingsProps {
    scrollSpeed: number;
}

const NeonRings: React.FC<NeonRingsProps> = ({ scrollSpeed }) => {
    const groupRef = useRef<THREE.Group>(null!);
    const conveyorLength = 300;
    const totalRings = 32; 
    const ringSpacing = conveyorLength / totalRings;

    useFrame((_, delta) => {
        if (groupRef.current) {
            groupRef.current.position.z = (groupRef.current.position.z + delta * scrollSpeed) % ringSpacing;
        }
    });

    const rings = useMemo(() => {
         return Array.from({ length: totalRings * 2 }).map((_, i) => {
            const isMeasureLine = i % 16 === 0;
            return (
                <mesh key={i} position={[0, 15, -i * ringSpacing]}>
                    <torusGeometry args={[40, 1, 8, 48]} />
                    <meshBasicMaterial
                        color={isMeasureLine ? 0xffff00 : 0x00ffff}
                        blending={THREE.AdditiveBlending}
                        transparent
                        opacity={isMeasureLine ? 0.9 : 0.6}
                        fog={false}
                    />
                </mesh>
            );
        });
    }, [ringSpacing]);

    return (
        <group ref={groupRef} position-z={0}>
           {rings}
        </group>
    );
};

export default NeonRings;
