import * as THREE from 'three';
import { useFrame } from '@react-three/fiber';
import { CONVEYOR_WIDTH } from '../constants';

const Buildings = React.memo(() => {
    const buildingMat = useMemo(() => new THREE.MeshStandardMaterial({ color: 0x1a001a, roughness: 0.8, metalness: 0.2 }), []);

    const buildings = useMemo(() => {
        return Array.from({ length: 40 }).map((_, i) => {
            const buildingHeight = Math.random() * 150 + 50;
            const buildingRadius = Math.random() * 8 + 4;
            const buildingGeo = new THREE.CylinderGeometry(0.1, buildingRadius, buildingHeight, 8);
            const side = Math.random() > 0.5 ? 1 : -1;
            const position = new THREE.Vector3(
                side * (CONVEYOR_WIDTH / 2 + 30 + Math.random() * 100),
                buildingHeight / 2 - 10,
                (Math.random() - 0.5) * 2000
            );
            const rotation = new THREE.Euler((Math.random() - 0.5) * 0.1, 0, (Math.random() - 0.5) * 0.1);
            return { key: i, position, rotation, geometry: buildingGeo };
        });
    }, []);

    return <>{buildings.map(b => <mesh key={b.key} position={b.position} rotation={b.rotation} geometry={b.geometry} material={buildingMat} />)}</>;
});

const Asteroids = React.memo(() => {
    const instancedMeshRef = useRef<THREE.InstancedMesh>(null!);
    const dummy = useMemo(() => new THREE.Object3D(), []);

    useMemo(() => {
        if (!instancedMeshRef.current) return;
        const asteroidGeo = new THREE.IcosahedronGeometry(1, 0);
        for (let i = 0; i < 200; i++) {
            const pos = new THREE.Vector3(
                (Math.random() - 0.5) * 1500,
                (Math.random() - 0.5) * 1000,
                (Math.random() - 0.5) * 2000
            );
            if (pos.length() < 300) pos.normalize().multiplyScalar(300 + Math.random() * 500);

            dummy.position.copy(pos);
            const scale = Math.random() * 10 + 5;
            dummy.scale.set(scale, scale, scale);
            dummy.rotation.set(Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI);
            dummy.updateMatrix();
            instancedMeshRef.current.setMatrixAt(i, dummy.matrix);
        }
        instancedMeshRef.current.instanceMatrix.needsUpdate = true;
    }, []);

    return (
        <instancedMesh ref={instancedMeshRef} args={[new THREE.IcosahedronGeometry(1,0), new THREE.MeshStandardMaterial({color: 0x200030, roughness: 0.8, metalness: 0.1}), 200]} />
    );
});

const Scenery: React.FC<{ scrollSpeed: number }> = ({ scrollSpeed }) => {
    const buildingGroup = useRef<THREE.Group>(null!);
    const asteroidGroup = useRef<THREE.Group>(null!);
    const loopDistance = 2000;

    useFrame((_, delta) => {
        if (!scrollSpeed) return;
        const scrollAmount = delta * scrollSpeed;
        if (buildingGroup.current) buildingGroup.current.position.z = (buildingGroup.current.position.z + scrollAmount);
        if (buildingGroup.current.position.z > loopDistance / 2) buildingGroup.current.position.z -= loopDistance;

        if (asteroidGroup.current) asteroidGroup.current.position.z = (asteroidGroup.current.position.z + scrollAmount * 0.8);
        if (asteroidGroup.current.position.z > loopDistance / 2) asteroidGroup.current.position.z -= loopDistance;
    });

    return (
        <>
            <group ref={buildingGroup} position-z={-loopDistance / 2}><Buildings /></group>
            <group ref={asteroidGroup} position-z={-loopDistance / 2}><Asteroids /></group>
        </>
    );
};

export default Scenery;
