import { InstrumentType } from './types';

export const NUM_STEPS = 32;
export const NUM_TRACKS = 16;
export const CONVEYOR_WIDTH = 60;
export const CONVEYOR_LENGTH = 300;

export const NOTES = [
    // Drums (indices 0-3)
    'C2', 'G2', 'C3', 'G3',
    // Melodic / Vocal (indices 4-15)
    'C4', 'D4', 'E4', 'F4',
    'G4', 'A4', 'B4', 'C5',
    'D5', 'E5', 'F5', 'G5',
];

export const TRACK_NAMES = [
    'Kick', 'Snare', 'Hat', 'Tom',
    'Bass', 'Synth 1', 'Synth 2', 'Synth 3',
    'Lead 1', 'Lead 2', 'Lead 3', 'Lead 4',
    'Vocal 1', 'Vocal 2', 'Vocal 3', 'Vocal 4'
];

export const BPM_MIN = 60;
export const BPM_MAX = 240;
export const DEFAULT_BPM = 120;

export const KEY_TO_NOTE_MAP: { [key: string]: number } = {
  'a': 4, 's': 5, 'd': 6, 'f': 7, 'g': 8, 'h': 9, 'j': 10, 'k': 11,
  'q': 12, 'w': 13, 'e': 14, 'r': 15, 't': 0, 'y': 1, 'u': 2, 'i': 3
};

export const INSTRUMENTS: InstrumentType[] = [
    'Sine', 'Square', 'Sawtooth', 'Triangle', 'FMSynth', 'AMSynth'
];

// SHADERS
export const snoise = `
vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec4 mod289(vec4 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec4 permute(vec4 x) { return mod289(((x*34.0)+1.0)*x); }
vec4 taylorInvSqrt(vec4 r) { return 1.79284291400159 - 0.85373472095314 * r; }
float snoise(vec3 v) {
    const vec2 C = vec2(1.0/6.0, 1.0/3.0); const vec4 D = vec4(0.0, 0.5, 1.0, 2.0);
    vec3 i = floor(v + dot(v, C.yyy)); vec3 x0 = v - i + dot(i, C.xxx);
    vec3 g = step(x0.yzx, x0.xyz); vec3 l = 1.0 - g;
    vec3 i1 = min(g.xyz, l.zxy); vec3 i2 = max(g.xyz, l.zxy);
    vec3 x1 = x0 - i1 + C.xxx; vec3 x2 = x0 - i2 + C.yyy; vec3 x3 = x0 - D.yyy;
    i = mod289(i);
    vec4 p = permute( permute( permute( i.z + vec4(0.0, i1.z, i2.z, 1.0 )) + i.y + vec4(0.0, i1.y, i2.y, 1.0 )) + i.x + vec4(0.0, i1.x, i2.x, 1.0 ));
    float n_ = 1.0/7.0; vec3 ns = n_ * D.wyz - D.xzx;
    vec4 j = p - 49.0 * floor(p * ns.z * ns.z);
    vec4 x_ = floor(j * ns.z); vec4 y_ = floor(j - 7.0 * x_);
    vec4 x = x_ * ns.x + ns.yyyy; vec4 y = y_ * ns.x + ns.yyyy;
    vec4 h = 1.0 - abs(x) - abs(y); vec4 b0 = vec4(x.xy, y.xy); vec4 b1 = vec4(x.zw, y.zw);
    vec4 s0 = floor(b0)*2.0 + 1.0; vec4 s1 = floor(b1)*2.0 + 1.0;
    vec4 sh = -step(h, vec4(0.0));
    vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy; vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww;
    vec3 p0 = vec3(a0.xy,h.x); vec3 p1 = vec3(a0.zw,h.y); vec3 p2 = vec3(a1.xy,h.z); vec3 p3 = vec3(a1.zw,h.w);
    vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
    p0 *= norm.x; p1 *= norm.y; p2 *= norm.z; p3 *= norm.w;
    vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
    m = m*m; return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1), dot(p2,x2), dot(p3,x3) ) );
}`;

export const CONVEYOR_V_SHADER = `
    uniform float uTime;
    uniform float uScrollOffset;
    varying vec2 vUv;
    varying vec2 vScrolledUv;
    varying float vTopoNoise;
    ${snoise}
    void main() {
        vUv = uv;
        // Use PLUS uScrollOffset to move grid *toward* viewer
        vScrolledUv = vec2(uv.x, fract(uv.y + uScrollOffset));
        vec3 pos = position;
        vTopoNoise = snoise(vec3(pos.x * 0.05, pos.z * 0.05, uTime * 0.1));
        pos.y += vTopoNoise * 3.0;
        gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
    }`;

export const CONVEYOR_F_SHADER = `
    uniform float uTime;
    uniform sampler2D uSeqGridTexture;
    uniform vec3 uPadColors[${NUM_TRACKS}];
    varying vec2 vUv;
    varying vec2 vScrolledUv;
    varying float vTopoNoise;

    float grid(vec2 uv, float stepsX, float stepsY, float width) {
        vec2 gridUV = fract(uv * vec2(stepsX, stepsY));
        vec2 dist = min(gridUV, 1.0 - gridUV) * 2.0;
        float lineX = smoothstep(width, 0.0, dist.x);
        float lineY = smoothstep(width, 0.0, dist.y);
        return max(lineX, lineY);
    }

    void main() {
        float isActive = texture2D(uSeqGridTexture, vScrolledUv).r;

        int trackIndex = int(vUv.x * ${NUM_TRACKS}.0);
        vec3 activeColor = uPadColors[trackIndex];

        vec3 baseColor = 0.3 + 0.2 * cos(vTopoNoise * 5.0 + uTime * 0.5 + vec3(0.0, 1.0, 2.0));

        vec3 color = mix(baseColor, activeColor, isActive);

        if (isActive > 0.5) {
            color += activeColor * (sin(uTime * 5.0) * 0.2 + 0.3);
        }

        float gridLines = grid(vScrolledUv, ${NUM_TRACKS}.0, ${NUM_STEPS}.0, 0.15);
        vec3 gridColor = 0.5 + 0.5 * sin(uTime * 1.0 + vUv.x * 5.0 + vScrolledUv.y * 10.0 + vec3(0.0, 0.4, 0.8));

        float opacity = 1.0 - (gridLines * 0.85);

        if (gridLines > 0.1) {
            color = gridColor * 0.5;
        }

        gl_FragColor = vec4(color, opacity);
    }`;

export const SKY_V_SHADER = `
    uniform float time;
    varying vec3 vWorldPosition;
    void main() {
        vec3 rotatedPosition = position;
        rotatedPosition.xz = vec2(
            position.x * cos(time * 0.005) - position.z * sin(time * 0.005),
            position.x * sin(time * 0.005) + position.z * cos(time * 0.005)
        );
        vec4 worldPosition = modelMatrix * vec4( rotatedPosition, 1.0 );
        vWorldPosition = worldPosition.xyz;
        gl_Position = projectionMatrix * modelViewMatrix * vec4( position, 1.0 );
    }
`;

export const SKY_F_SHADER = `
    uniform float time;
    varying vec3 vWorldPosition;
    ${snoise}    
    void main() {
        vec3 pos = normalize(vWorldPosition);

        float noise1 = snoise(pos * 2.0 + time * 0.05);
        float noise2 = snoise(pos * 5.0 + time * 0.1);
        float noise = (noise1 + noise2) * 0.5;
        noise = (noise * 0.5 + 0.5);  

        vec3 color1 = vec3(0.0, 0.0, 0.1);
        vec3 color2 = vec3(0.6, 0.1, 0.8);
        vec3 color3 = vec3(0.0, 0.3, 0.7);
        vec3 color4 = vec3(1.0, 0.3, 0.6);

        float t = abs(pos.y);  
        vec3 mixed_color = mix(color1, color2, noise);  
        mixed_color = mix(mixed_color, color3, t * 0.5);
        mixed_color = mix(mixed_color, color4, noise * noise * 0.5);

        float pulse = sin(time * 0.5 + pos.x * 2.0) * 0.15 + 0.85;
        mixed_color *= pulse;

        gl_FragColor = vec4(mixed_color, 1.0);
    }
`;
