import { Canvas } from '@react-three/fiber';

import { SequencerGrid, PlayMode, MuteSoloState, FXSettings, TrackSettings } from './types';
import { NUM_STEPS, NUM_TRACKS, NOTES, KEY_TO_NOTE_MAP, DEFAULT_BPM } from './constants';

import StartModal from './components/StartModal';
import AudioWarning from './components/AudioWarning';
import ControlPanel from './components/ControlPanel';
import ConveyorBelt from './components/ConveyorBelt';
import NeonRings from './components/NeonRings';
import CameraRig from './components/CameraRig';
import Skybox from './components/Skybox';
import Starfield from './components/Starfield';
import Scenery from './components/Scenery';
import EQBars from './components/EQBars';
import Playhead from './components/Playhead';

const createEmptyGrid = (): SequencerGrid => Array.from({ length: NUM_TRACKS }, () => Array(NUM_STEPS).fill(false));
const createInitialMuteSolo = (): MuteSoloState => Array.from({ length: NUM_TRACKS }, () => ({ mute: false, solo: false }));
const createInitialTrackSettings = (): TrackSettings[] => Array.from({ length: NUM_TRACKS }, (_, i) => ({
    instrument: i < 4 ? 'MembraneSynth' : 'Sine',
}));

const App: React.FC = () => {
    const [isInitialized, setIsInitialized] = useState(false);
    const [grid, setGrid] = useState<SequencerGrid>(createEmptyGrid);
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentStep, setCurrentStep] = useState(-1);
    const [bpm, setBpm] = useState(DEFAULT_BPM);
    const [playMode, setPlayMode] = useState<PlayMode>(PlayMode.DIRECT_PLAY);
    const [audioWarning, setAudioWarning] = useState('');
    const [scrollOffset, setScrollOffset] = useState(0);

    const [muteSolo, setMuteSolo] = useState<MuteSoloState>(createInitialMuteSolo);
    const [fxSettings, setFxSettings] = useState<FXSettings>({ reverb: 0.1, delay: 0.1 });
    const [trackSettings, setTrackSettings] = useState<TrackSettings[]>(createInitialTrackSettings());
    const [volumes, setVolumes] = useState<number[]>(() => Array(NUM_TRACKS).fill(-6));
    const [meters, setMeters] = useState<number[]>(() => Array(NUM_TRACKS).fill(-Infinity));

    const [musicVolume, setMusicVolume] = useState(0.5);
    const [sfxVolume, setSfxVolume] = useState(0.8);
    const [mouseSpeed, setMouseSpeed] = useState(1.0);

    const liveAudioLevels = useRef(new Array(NUM_TRACKS).fill(0.0)).current;

    const gridRef = useRef(grid);
    useEffect(() => { gridRef.current = grid; }, [grid]);
    const muteSoloRef = useRef(muteSolo);
    useEffect(() => { muteSoloRef.current = muteSolo; }, [muteSolo]);

    const isPlayingRef = useRef(isPlaying);
    useEffect(() => { isPlayingRef.current = isPlaying; }, [isPlaying]);
    const currentStepRef = useRef(currentStep);
    useEffect(() => { currentStepRef.current = currentStep; }, [currentStep]);
    const playModeRef = useRef(playMode);
    useEffect(() => { playModeRef.current = playMode; }, [playMode]);

    const audioCtx = useRef({
        synths: [] as (Tone.Synth | Tone.MembraneSynth | Tone.FMSynth | Tone.AMSynth | Tone.MetalSynth)[],
        channels: [] as Tone.Channel[],
        meters: [] as Tone.Meter[],
        reverb: null as Tone.Reverb | null,
        delay: null as Tone.PingPongDelay | null,
        musicBus: null as Tone.Volume | null,
        sfxBus: null as Tone.Volume | null,
        startSound: null as Tone.Synth | null,
    }).current;

    const mapVolume = (value: number, out_min: number, out_max: number) => {
        if (value <= 0.01) return -Infinity;
        const min_log = Math.log(0.01);
        const max_log = Math.log(1);
        const scale = (Math.log(value) - min_log) / (max_log - min_log);
        return scale * (out_max - out_min) + out_min;
    };

    const initializeAudio = useCallback(async () => {
        try {
            await Tone.start();

            // Create master busses
            const masterBus = new Tone.Volume(0).toDestination();
            audioCtx.reverb = new Tone.Reverb({ decay: 4, wet: fxSettings.reverb }).connect(masterBus);
            audioCtx.delay = new Tone.PingPongDelay({ delayTime: '8n', feedback: 0.5, wet: fxSettings.delay }).connect(masterBus);

            // Create main busses for SFX and Music
            audioCtx.sfxBus = new Tone.Volume(mapVolume(sfxVolume, -30, 0)).connect(masterBus);
            audioCtx.musicBus = new Tone.Volume(mapVolume(musicVolume, -40, -10)).connect(masterBus);
            audioCtx.sfxBus.connect(audioCtx.reverb);
            audioCtx.musicBus.connect(audioCtx.reverb);

            // Start Sound
            audioCtx.startSound = new Tone.Synth({
                oscillator:{type:'fatsawtooth',count:3,spread:30},
                envelope:{attack:0.1,decay:0.5,sustain:0.2,release:0.5}
            }).connect(audioCtx.sfxBus);
            audioCtx.startSound.volume.value = -6;

            // Ambient Drones
            new Tone.Oscillator("C2", "sine").connect(audioCtx.musicBus).start();
            const highDrone = new Tone.FMSynth({
                harmonicity:3, modulationIndex:5, oscillator:{type:"sine"},
                envelope:{attack:4,decay:1,sustain:1,release:4},
                modulation:{type:"square"},
                modulationEnvelope:{attack:4,decay:0.1,sustain:1,release:4}
            }).connect(audioCtx.musicBus);
            highDrone.triggerAttack("C5");

            trackSettings.forEach((setting, i) => {
                const channel = new Tone.Channel(volumes[i]);
                const meter = new Tone.Meter();
                channel.connect(meter);
                channel.connect(audioCtx.sfxBus!);

                audioCtx.channels[i] = channel;
                audioCtx.meters[i] = meter;

                let synth: any;
                if (setting.instrument === 'MembraneSynth') synth = new Tone.MembraneSynth();
                else if (setting.instrument === 'FMSynth') synth = new Tone.FMSynth();
                else if (setting.instrument === 'AMSynth') synth = new Tone.AMSynth();
                else if (setting.instrument === 'MetalSynth') synth = new Tone.MetalSynth();
                else synth = new Tone.Synth({ oscillator: { type: setting.instrument.toLowerCase() as any } });

                synth.connect(channel);
                audioCtx.synths[i] = synth;
            });

            new Tone.Sequence((time, step) => {
                const currentGrid = gridRef.current;
                const currentMuteSolo = muteSoloRef.current;
                const anySolo = currentMuteSolo.some(s => s.solo);
                currentGrid.forEach((track, trackIndex) => {
                    if (track[step] && !currentMuteSolo[trackIndex].mute && (!anySolo || currentMuteSolo[trackIndex].solo)) {
                         audioCtx.synths[trackIndex]?.triggerAttackRelease(NOTES[trackIndex], '16n', time);
                    }
                });
                Tone.Draw.schedule(() => setCurrentStep(step), time);
            }, Array.from({ length: NUM_STEPS }, (_, i) => i), '16n').start(0);

            Tone.Transport.bpm.value = bpm;
            setIsInitialized(true);
            audioCtx.startSound.triggerAttackRelease("C3", "1s");
        } catch(e) {
            setAudioWarning("Audio could not be initialized.");
            console.error(e);
        }
    }, [audioCtx, bpm, fxSettings, trackSettings, volumes, sfxVolume, musicVolume]);

    // Metering loop
    useEffect(() => {
        if (!isInitialized || !isPlaying) return;
        const interval = setInterval(() => setMeters(audioCtx.meters.map(m => m.getValue() as number)), 100);
        return () => clearInterval(interval);
    }, [isInitialized, isPlaying, audioCtx.meters]);

    useEffect(() => { isPlaying ? Tone.Transport.start() : Tone.Transport.stop(); }, [isPlaying]);
    useEffect(() => { Tone.Transport.bpm.value = bpm; }, [bpm]);
    useEffect(() => { if(audioCtx.reverb) audioCtx.reverb.wet.value = fxSettings.reverb; }, [fxSettings.reverb, audioCtx.reverb]);
    useEffect(() => { if(audioCtx.delay) audioCtx.delay.wet.value = fxSettings.delay; }, [fxSettings.delay, audioCtx.delay]);
    useEffect(() => { volumes.forEach((v, i) => audioCtx.channels[i]?.volume.rampTo(v, 0.1)); }, [volumes, audioCtx.channels]);
    useEffect(() => { if (audioCtx.sfxBus) audioCtx.sfxBus.volume.value = mapVolume(sfxVolume, -30, 0); }, [sfxVolume, audioCtx.sfxBus]);
    useEffect(() => { if (audioCtx.musicBus) audioCtx.musicBus.volume.value = mapVolume(musicVolume, -40, -10); }, [musicVolume, audioCtx.musicBus]);


    useEffect(() => {
        if (!isInitialized) return;
        trackSettings.forEach((setting, i) => {
            if (!audioCtx.synths[i] || audioCtx.synths[i].name === setting.instrument) return;

            audioCtx.synths[i]?.dispose();
            let newSynth: any;
            if (setting.instrument === 'FMSynth') newSynth = new Tone.FMSynth();
            else if (setting.instrument === 'AMSynth') newSynth = new Tone.AMSynth();
            else if (setting.instrument === 'MetalSynth') newSynth = new Tone.MetalSynth();
            else newSynth = new Tone.Synth({ oscillator: { type: setting.instrument.toLowerCase() as any }});

            newSynth.connect(audioCtx.channels[i]);
            audioCtx.synths[i] = newSynth;
        });
    }, [trackSettings, isInitialized, audioCtx]);

    const activeKeys = useRef(new Set()).current;

    useEffect(() => {
        if (!isInitialized) return;

        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.repeat || document.activeElement?.tagName === 'SELECT' || document.activeElement?.tagName === 'INPUT') return;
            const key = e.key.toLowerCase();
            const trackIndex = KEY_TO_NOTE_MAP[key];

            if (trackIndex !== undefined && !activeKeys.has(key)) {
                e.preventDefault();
                activeKeys.add(key);

                if (playModeRef.current === PlayMode.DIRECT_PLAY) {
                    if (trackIndex <= 3) { // Drums are one-shots
                        audioCtx.synths[trackIndex]?.triggerAttackRelease(NOTES[trackIndex], '8n', Tone.now());
                    } else { // Melodic are held
                        audioCtx.synths[trackIndex]?.triggerAttack(NOTES[trackIndex], Tone.now());
                    }
                } else { // Sequencer Mode - play note AND toggle grid
                     audioCtx.synths[trackIndex]?.triggerAttackRelease(NOTES[trackIndex], '8n', Tone.now());
                     if (isPlayingRef.current && currentStepRef.current >= 0) {
                         const step = currentStepRef.current;
                         setGrid(g => {
                             const newGrid = g.map(t => [...t]);
                             newGrid[trackIndex][step] = !newGrid[trackIndex][step];
                             return newGrid;
                         });
                     }
                }
                liveAudioLevels[trackIndex] = 1.0;
            }
        };

        const handleKeyUp = (e: KeyboardEvent) => {
             const key = e.key.toLowerCase();
             const trackIndex = KEY_TO_NOTE_MAP[key];

             if (trackIndex !== undefined && activeKeys.has(key)) {
                e.preventDefault();
                activeKeys.delete(key);
                if (playModeRef.current === PlayMode.DIRECT_PLAY && trackIndex > 3) {
                     audioCtx.synths[trackIndex]?.triggerRelease(Tone.now());
                }
             }
        };

        window.addEventListener('keydown', handleKeyDown);
        window.addEventListener('keyup', handleKeyUp);
        return () => {
            window.removeEventListener('keydown', handleKeyDown);
            window.removeEventListener('keyup', handleKeyUp);
        }
    }, [isInitialized, audioCtx, activeKeys, liveAudioLevels]);


    useEffect(() => {
        if (!isPlaying) { 
            const timer = setTimeout(() => {
                if(!isPlaying) {
                    setScrollOffset(0);
                    setCurrentStep(-1);
                }
            }, 200);
            return () => clearTimeout(timer);
        }
        let frameId: number;
        const update = () => {
            setScrollOffset(Tone.Transport.progress);
            frameId = requestAnimationFrame(update);
        };
        frameId = requestAnimationFrame(update);
        return () => cancelAnimationFrame(frameId);
    }, [isPlaying]);

    const onClearGrid = useCallback(() => {
        setGrid(createEmptyGrid());
    }, []);

    const scrollSpeed = isPlaying ? (bpm / 60) * 20 : 0;

    return (
        <div className="w-screen h-screen">
            <Canvas camera={{ position: [0, 30, 80], fov: 75 }} shadows>
                <Skybox />
                <Starfield />
                <Scenery scrollSpeed={scrollSpeed} />
                <fog attach="fog" args={['#000010', 100, 400]} />
                <ambientLight intensity={0.5} />
                <pointLight position={[10, 50, 50]} intensity={2} castShadow />

                {isInitialized && (
                    <>
                       <ConveyorBelt grid={grid} scrollOffset={scrollOffset} />
                       <EQBars grid={grid} setGrid={setGrid} scrollOffset={scrollOffset} liveAudioLevels={liveAudioLevels}/>
                       <NeonRings scrollSpeed={isPlaying ? (bpm / 60) * (300 / (NUM_STEPS / 4)) : 0} />
                       <Playhead />
                    </>
                )}
                <CameraRig mouseSpeed={mouseSpeed} />
            </Canvas>

            <StartModal isVisible={!isInitialized} onStartClick={initializeAudio} />
            <AudioWarning isVisible={!!audioWarning} text={audioWarning} />

            {isInitialized && (
                <ControlPanel
                    grid={grid}
                    setGrid={setGrid}
                    isPlaying={isPlaying}
                    onPlayToggle={() => setIsPlaying(p => !p)}
                    bpm={bpm}
                    setBpm={setBpm}
                    playMode={playMode}
                    setPlayMode={setPlayMode}
                    onClearGrid={onClearGrid}
                    currentStep={currentStep}
                    muteSolo={muteSolo}
                    setMuteSolo={setMuteSolo}
                    fxSettings={fxSettings}
                    setFxSettings={setFxSettings}
                    trackSettings={trackSettings}
                    setTrackSettings={setTrackSettings}
                    volumes={volumes}
                    setVolumes={setVolumes}
                    meters={meters}
                    musicVolume={musicVolume}
                    setMusicVolume={setMusicVolume}
                    sfxVolume={sfxVolume}
                    setSfxVolume={setSfxVolume}
                    mouseSpeed={mouseSpeed}
                    setMouseSpeed={setMouseSpeed}
                />
            )}
        </div>
    );
};

export default App;
