import React, { useMemo } from 'react';
import { SequencerGrid, PlayMode, MuteSoloState, FXSettings, TrackSettings, InstrumentType } from '../types';
import { BPM_MIN, BPM_MAX, INSTRUMENTS, NUM_STEPS, TRACK_NAMES } from '../constants';

interface ControlPanelProps {
    grid: SequencerGrid;
    setGrid: (grid: SequencerGrid) => void;
    isPlaying: boolean;
    onPlayToggle: () => void;
    bpm: number;
    setBpm: (bpm: number) => void;
    playMode: PlayMode;
    setPlayMode: (mode: PlayMode) => void;
    onClearGrid: () => void;
    currentStep: number;
    muteSolo: MuteSoloState;
    setMuteSolo: (state: MuteSoloState) => void;
    fxSettings: FXSettings;
    setFxSettings: (settings: FXSettings) => void;
    trackSettings: TrackSettings[];
    setTrackSettings: (settings: TrackSettings[]) => void;
    volumes: number[];
    setVolumes: (volumes: number[]) => void;
    meters: number[];
    musicVolume: number;
    setMusicVolume: (vol: number) => void;
    sfxVolume: number;
    setSfxVolume: (vol: number) => void;
    mouseSpeed: number;
    setMouseSpeed: (speed: number) => void;
}

const mapDbToHeight = (db: number) => {
    const meterMinDb = -60;
    if (db < meterMinDb) return 0;
    return ((db - meterMinDb) / -meterMinDb) * 100;
};

const ControlPanel: React.FC<ControlPanelProps> = ({
    grid, setGrid, isPlaying, onPlayToggle, bpm, setBpm, playMode, setPlayMode, onClearGrid, currentStep,
    muteSolo, setMuteSolo, fxSettings, setFxSettings, trackSettings, setTrackSettings, volumes, setVolumes, meters,
    musicVolume, setMusicVolume, sfxVolume, setSfxVolume, mouseSpeed, setMouseSpeed,
}) => {
    const activeNotes = useMemo(() => grid.flat().filter(Boolean).length, [grid]);
    const progress = currentStep < 0 ? 0 : ((currentStep + 1) / NUM_STEPS) * 100;

    const handleGridClick = (trackIndex: number, stepIndex: number) => {
        const newGrid = grid.map(t => [...t]);
        newGrid[trackIndex][stepIndex] = !newGrid[trackIndex][stepIndex];
        setGrid(newGrid);
    };

    const handleMute = (trackIndex: number) => {
        const newState = muteSolo.map(s => ({...s}));
        newState[trackIndex].mute = !newState[trackIndex].mute;
        setMuteSolo(newState);
    };

    const handleSolo = (trackIndex: number) => {
        const newState = muteSolo.map(s => ({...s}));
        const isSoloing = !newState[trackIndex].solo;
        if (isSoloing) {
            newState.forEach((s, i) => { if (i !== trackIndex) s.solo = false; });
        }
        newState[trackIndex].solo = isSoloing;
        setMuteSolo(newState);
    };

    const handleVolumeChange = (trackIndex: number, value: number) => {
        const newVolumes = [...volumes];
        newVolumes[trackIndex] = value;
        setVolumes(newVolumes);
    };

    const handleInstrumentChange = (trackIndex: number, instrument: InstrumentType) => {
        const newSettings = [...trackSettings];
        newSettings[trackIndex].instrument = instrument;
        setTrackSettings(newSettings);
    };

    return (
        <div className="fixed bottom-0 left-0 w-full h-[420px] sm:h-[380px] pointer-events-none z-10 [perspective:1500px]">
            <div
                className="relative w-full h-full pointer-events-auto bg-gray-900/80 backdrop-blur-lg border-t-2 border-cyan-400/50 shadow-[0_-10px_50px_rgba(0,255,255,0.2)] rounded-t-3xl [transform-origin:bottom_center] [transform:rotateX(55deg)_scale(0.95)]"
            >
                <div className="absolute inset-0 bg-grid-cyan opacity-50"></div>
                <div className="w-full h-full p-4 flex flex-col sm:flex-row gap-4 text-white">
                    {/* Master & Settings Controls */}
                    <div className="w-full sm:w-1/3 flex flex-col gap-3">
                        <div className="flex-1 flex flex-col gap-3">
                            <h2 className="text-lg font-bold text-cyan-300 tracking-widest">MASTER</h2>
                            <div className="grid grid-cols-2 gap-2">
                                <button onClick={onPlayToggle} className={`py-2 rounded transition-colors text-black font-bold ${isPlaying ? 'bg-yellow-500 hover:bg-yellow-400' : 'bg-green-500 hover:bg-green-400'}`}>
                                    {isPlaying ? 'PAUSE' : 'PLAY'}
                                </button>
                                <button onClick={onClearGrid} className="py-2 bg-red-600 rounded hover:bg-red-500 transition-colors text-white font-bold">CLEAR</button>
                            </div>
                            <div className="flex flex-col">
                                <label className="text-sm text-gray-300">BPM: <span className="text-cyan-300">{bpm}</span></label>
                                <input type="range" min={BPM_MIN} max={BPM_MAX} value={bpm} onChange={(e) => setBpm(parseInt(e.target.value))} className="w-full" />
                            </div>
                            <button onClick={() => setPlayMode(playMode === PlayMode.SEQUENCER ? PlayMode.DIRECT_PLAY : PlayMode.SEQUENCER)} className="py-2 bg-purple-600 rounded hover:bg-purple-500 transition-colors">
                            MODE: {playMode}
                            </button>
                        </div>
                        <div className="flex-1 flex flex-col gap-2 mt-2">
                             <h2 className="text-lg font-bold text-cyan-300 tracking-widest">SETTINGS</h2>
                             <div className="grid grid-cols-2 gap-4">
                                <div className="flex flex-col">
                                    <label className="text-sm text-gray-300">Reverb</label>
                                    <input type="range" min="0" max="1" step="0.05" value={fxSettings.reverb} onChange={(e) => setFxSettings({...fxSettings, reverb: parseFloat(e.target.value)})} />
                                </div>
                                <div className="flex flex-col">
                                    <label className="text-sm text-gray-300">Delay</label>
                                    <input type="range" min="0" max="1" step="0.05" value={fxSettings.delay} onChange={(e) => setFxSettings({...fxSettings, delay: parseFloat(e.target.value)})} />
                                </div>
                                <div className="flex flex-col">
                                    <label className="text-sm text-gray-300">Drone Vol</label>
                                    <input type="range" min="0" max="1" step="0.05" value={musicVolume} onChange={(e) => setMusicVolume(parseFloat(e.target.value))} />
                                </div>
                                <div className="flex flex-col">
                                    <label className="text-sm text-gray-300">SFX Vol</label>
                                    <input type="range" min="0" max="1" step="0.05" value={sfxVolume} onChange={(e) => setSfxVolume(parseFloat(e.target.value))} />
                                </div>
                             </div>
                             <div className="flex flex-col">
                                <label className="text-sm text-gray-300">Sensitivity</label>
                                <input type="range" min="0.1" max="3" step="0.1" value={mouseSpeed} onChange={(e) => setMouseSpeed(parseFloat(e.target.value))} />
                            </div>
                        </div>
                    </div>

                    {/* Sequencer / Mixer */}
                    <div className="w-full sm:w-2/3 flex flex-col overflow-hidden">
                        <div className='flex justify-between items-center mb-1'>
                            <h2 className="text-lg font-bold text-cyan-300 tracking-widest">SEQUENCER / MIXER</h2>
                            <div className='flex gap-4 items-center'>
                                <div className="text-gray-400 text-sm">Active: <span className="font-mono font-bold text-cyan-300">{activeNotes}</span></div>
                                <div className="text-gray-400 text-sm">Pos: <span className="font-mono text-cyan-300">{currentStep < 0 ? 0 : currentStep + 1}/{NUM_STEPS}</span></div>
                                <div className="w-24 bg-black/30 rounded-full h-2 border border-cyan-800">
                                    <div className="bg-gradient-to-r from-cyan-400 to-purple-500 h-full rounded-full transition-all duration-100" style={{width: `${progress}%`}}></div>
                                </div>
                            </div>
                        </div>
                        <div className="flex-1 flex flex-col gap-1.5 bg-black/40 p-2 rounded-lg overflow-y-auto">
                            {TRACK_NAMES.map((name, trackIndex) => (
                                <div key={trackIndex} className="flex-1 flex items-center gap-2 min-h-[24px]">
                                    <div className="w-24 sm:w-28 text-xs text-right text-gray-300 truncate">{name}</div>
                                    <button onClick={() => handleMute(trackIndex)} className={`w-6 h-5 text-xs rounded transition-colors ${muteSolo[trackIndex].mute ? 'bg-yellow-500 text-black' : 'bg-gray-600 hover:bg-gray-500'}`}>M</button>
                                    <button onClick={() => handleSolo(trackIndex)} className={`w-6 h-5 text-xs rounded transition-colors ${muteSolo[trackIndex].solo ? 'bg-blue-500 text-white' : 'bg-gray-600 hover:bg-gray-500'}`}>S</button>

                                    {trackIndex >= 4 ? (
                                        <select
                                           value={trackSettings[trackIndex].instrument}
                                           onChange={(e) => handleInstrumentChange(trackIndex, e.target.value as InstrumentType)}
                                           className="w-24 bg-gray-700 text-xs rounded p-1 border border-gray-600 h-full">
                                           {INSTRUMENTS.map(inst => <option key={inst} value={inst}>{inst}</option>)}
                                        </select>
                                    ) : (
                                        <div className="w-24"></div>
                                    )}

                                    <input
                                      type="range"
                                      min={-48}
                                      max={6}
                                      step={1}
                                      value={volumes[trackIndex]}
                                      onChange={(e) => handleVolumeChange(trackIndex, parseInt(e.target.value))}
                                      className="w-20 mx-2"
                                    />

                                    <div className="flex-1 grid grid-cols-32 gap-1 h-full relative">
                                        {Array.from({length: NUM_STEPS}).map((_, stepIndex) => (
                                            <div
                                                key={stepIndex}
                                                onClick={() => handleGridClick(trackIndex, stepIndex)}
                                                className={`h-full rounded-sm cursor-pointer transition-colors ${
                                                    grid[trackIndex]?.[stepIndex] ? 'bg-cyan-400 shadow-[0_0_4px_#0ff]' : 'bg-gray-700/50 hover:bg-gray-600/50'
                                                }`}
                                            ></div>
                                        ))}
                                         {isPlaying && currentStep >=0 && <div className="absolute top-0 bottom-0 bg-white/50 w-0.5" style={{ left: `${(currentStep / NUM_STEPS) * 100}%`}}></div>}
                                    </div>
                                    <div className="w-16 h-full bg-gray-800 rounded overflow-hidden border border-gray-600 relative">
                                        <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-green-600 via-yellow-400 to-red-500 transition-all duration-50" style={{height: `${mapDbToHeight(meters[trackIndex])}%`}}></div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ControlPanel;
