import React, { useRef, useMemo, useEffect } from 'react';
import * as THREE from 'three';
import { useFrame } from '@react-three/fiber';
import { SequencerGrid } from '../types';
import { NUM_STEPS, NUM_TRACKS, CONVEYOR_V_SHADER, CONVEYOR_F_SHADER } from '../constants';

const padColors = Array.from({ length: NUM_TRACKS }, (_, i) => {
    if (i < 4) return new THREE.Color().setHSL(0.5, 0.8, 0.5 + i * 0.1);
    return new THREE.Color().setHSL((i - 4) / (NUM_TRACKS - 4), 1.0, 0.6);
});

interface ConveyorBeltProps {
    grid: SequencerGrid;
    scrollOffset: number;
}

const ConveyorBelt: React.FC<ConveyorBeltProps> = ({ grid, scrollOffset }) => {
    const materialRef = useRef<THREE.ShaderMaterial>(null!);

    const texture = useMemo(() => {
        const data = new Uint8Array(NUM_STEPS * NUM_TRACKS * 4);
        const tex = new THREE.DataTexture(data, NUM_TRACKS, NUM_STEPS, THREE.RGBAFormat);
        tex.needsUpdate = true;
        return tex;
    }, []);

    useEffect(() => {
        const data = texture.image.data;
        let changed = false;
        for (let track = 0; track < NUM_TRACKS; track++) {
            for (let step = 0; step < NUM_STEPS; step++) {
                const index = (step * NUM_TRACKS + track) * 4;
                const isActive = grid[track]?.[step] ?? false;
                const currentVal = data[index];
                const targetVal = isActive ? 255 : 0;
                if (currentVal !== targetVal) {
                    data[index] = targetVal;
                    data[index+3] = 255;
                    changed = true;
                }
            }
        }
        if (changed) {
            texture.needsUpdate = true;
        }
    }, [grid, texture]);

    useFrame((state) => {
        if (materialRef.current) {
            materialRef.current.uniforms.uTime.value = state.clock.getElapsedTime();
            materialRef.current.uniforms.uScrollOffset.value = scrollOffset;
        }
    });

    return (
        <mesh rotation-x={-Math.PI / 2} position-y={-10}>
            <planeGeometry args={[60, 300, 64, 128]} />
            <shaderMaterial
                ref={materialRef}
                key={CONVEYOR_V_SHADER + CONVEYOR_F_SHADER}
                uniforms={{
                    uTime: { value: 0.0 },
                    uScrollOffset: { value: 0.0 },
                    uSeqGridTexture: { value: texture },
                    uPadColors: { value: padColors },
                }}
                vertexShader={CONVEYOR_V_SHADER}
                fragmentShader={CONVEYOR_F_SHADER}
                transparent={true}
            />
        </mesh>
    );
};

export default React.memo(ConveyorBelt);
