import React, { useRef, useEffect, useMemo } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import * as THREE from 'three';

interface CameraRigProps {
    mouseSpeed: number;
}

const CameraRig: React.FC<CameraRigProps> = ({ mouseSpeed }) => {
    const { camera, gl } = useThree();
    const orbitControlsRef = useRef<any>(null!);

    const euler = useMemo(() => new THREE.Euler(0, 0, 0, 'YXZ'), []);
    const cameraTarget = useMemo(() => new THREE.Vector3(0, 0, 0), []);
    const cameraBasePosition = useMemo(() => new THREE.Vector3(0, 30, 80), []);

    useFrame((state) => {
        const t = state.clock.getElapsedTime();

        // Calculate Orbit from right-click drag
        const orbitQuat = new THREE.Quaternion().setFromEuler(euler);

        // Calculate Roller Coaster "Sway"
        const swayMagnitude = 15;
        const lateralMagnitude = 10;
        const currentSwayX = Math.sin(t * 0.4) * swayMagnitude;
        const currentSwayY = Math.sin(t * 0.6) * swayMagnitude * 0.5;
        const currentLateral = Math.cos(t * 0.25) * lateralMagnitude;
        const dynamicOffset = new THREE.Vector3(currentSwayX + currentLateral, currentSwayY, 0);

        const swayedPos = new THREE.Vector3().copy(cameraBasePosition);

        // Apply orbit to the swayed position if not user-controlled
        if (!orbitControlsRef.current?.enabled) {
            swayedPos.add(dynamicOffset);
        }
        swayedPos.applyQuaternion(orbitQuat);

        camera.position.lerp(swayedPos, 0.1);

        // Look At logic
        cameraTarget.x = Math.sin(t * 0.3) * 3;
        cameraTarget.y = -5.0 + Math.cos(t * 0.4) * 2;
        cameraTarget.z = 0; 

        const lookAtTarget = new THREE.Vector3().copy(cameraTarget);
        lookAtTarget.applyQuaternion(orbitQuat); // Make the lookAt target respect the orbit

        // Final lookAt
        const targetPosition = new THREE.Vector3(0, 0, 0);
        camera.lookAt(targetPosition.lerp(lookAtTarget, 0.1));
    });

    useEffect(() => {
        const controls = orbitControlsRef.current;
        if (!controls) return;
        const canvas = gl.domElement;

        const handleMouseDown = (e: MouseEvent) => { if (e.button === 2) controls.enabled = true; };
        const handleMouseUp = (e: MouseEvent) => { if (e.button === 2) controls.enabled = false; };
        const handleContextMenu = (e: Event) => e.preventDefault();

        const handleMouseMove = (e: MouseEvent) => {
            if (controls.enabled) {
                euler.y -= e.movementX * 0.002 * mouseSpeed;
                euler.x -= e.movementY * 0.002 * mouseSpeed;
                euler.x = Math.max(-Math.PI / 2 + 0.1, Math.min(Math.PI / 2 - 0.1, euler.x));
            }
        };

        canvas.addEventListener('mousedown', handleMouseDown);
        canvas.addEventListener('mouseup', handleMouseUp);
        canvas.addEventListener('contextmenu', handleContextMenu);
        window.addEventListener('mousemove', handleMouseMove);

        return () => {
            canvas.removeEventListener('mousedown', handleMouseDown);
            canvas.removeEventListener('mouseup', handleMouseUp);
            canvas.removeEventListener('contextmenu', handleContextMenu);
            window.removeEventListener('mousemove', handleMouseMove);
        };
    }, [gl.domElement, euler, mouseSpeed]);

    return <OrbitControls ref={orbitControlsRef} enabled={false} enableZoom={false} enablePan={false} />;
};

export default CameraRig;
