import React, { useRef, useMemo, useEffect, useCallback } from 'react';
import * as THREE from 'three';
import { useFrame, useThree } from '@react-three/fiber';
import { SequencerGrid } from '../types';
import { NUM_STEPS, NUM_TRACKS, CONVEYOR_WIDTH, CONVEYOR_LENGTH } from '../constants';
import * as Tone from 'tone';

const padColors = Array.from({ length: NUM_TRACKS }, (_, i) => {
    if (i < 4) return new THREE.Color().setHSL(0.5, 0.8, 0.5 + i * 0.1); // Drums
    return new THREE.Color().setHSL((i - 4) / (NUM_TRACKS - 4), 1.0, 0.6); // Melodic
});

interface EQBarsProps {
    grid: SequencerGrid;
    setGrid: (grid: SequencerGrid) => void;
    scrollOffset: number;
    liveAudioLevels: number[];
}

const jsSmoothstep = (edge0: number, edge1: number, x: number) => {
    const t = Math.max(0, Math.min(1, (x - edge0) / (edge1 - edge0)));
    return t * t * (3 - 2 * t);
};

const EQBars: React.FC<EQBarsProps> = ({ grid, setGrid, scrollOffset, liveAudioLevels }) => {
    const meshRef = useRef<THREE.InstancedMesh>(null!);
    const { camera, gl } = useThree();
    const raycaster = useMemo(() => new THREE.Raycaster(), []);
    const dummy = useMemo(() => new THREE.Object3D(), []);

    const barStates = useRef(
        Array.from({ length: NUM_TRACKS * NUM_STEPS }, () => ({
            pop: 0,
        }))
    ).current;

    const padHitSound = useMemo(() => new Tone.Synth({
        oscillator: { type: "triangle" },
        envelope: { attack: 0.005, decay: 0.1, sustain: 0, release: 0.1 }
    }).toDestination(), []);
    padHitSound.volume.value = -10;

    const gridRef = useRef(grid);
    useEffect(() => { gridRef.current = grid; }, [grid]);
    const scrollOffsetRef = useRef(scrollOffset);
    useEffect(() => { scrollOffsetRef.current = scrollOffset; }, [scrollOffset]);

    useEffect(() => {
        if (!meshRef.current) return;
        let i = 0;
        for (let track = 0; track < NUM_TRACKS; track++) {
            for (let step = 0; step < NUM_STEPS; step++) {
                meshRef.current.setColorAt(i, padColors[track]);
                i++;
            }
        }
        if(meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
    }, []);

    useFrame((state, delta) => {
        if (!meshRef.current) return;
        const segmentLength = CONVEYOR_LENGTH / NUM_STEPS;
        const beltBaseZ = -CONVEYOR_LENGTH / 2;

        for (let i = 0; i < NUM_TRACKS * NUM_STEPS; i++) {
            const track = i % NUM_TRACKS;
            const step = Math.floor(i / NUM_TRACKS);

            // 1. Calculate scrolled Z position
            const xPos = (track / NUM_TRACKS - 0.5 + 0.5 / NUM_TRACKS) * CONVEYOR_WIDTH;
            const baseV = step / NUM_STEPS;
            const scrolledV = baseV + scrollOffset;
            const wrappedV = (scrolledV + 1.0) % 1.0;
            const zPos = beltBaseZ + (wrappedV + 0.5 / NUM_STEPS) * CONVEYOR_LENGTH;

            // 2. Animate bar height
            const barState = barStates[i];
            const isActive = grid[track]?.[step] ?? false;

            const sequencerBaseHeight = isActive ? 1.5 + Math.sin(state.clock.elapsedTime * 5 + i * 0.5) * 1.5 : 0.1;

            // 3. Calculate live EQ height from keyboard presses
            const playheadDist = Math.abs(zPos - 0);
            const playheadWindow = segmentLength * 2.0;
            const eqIntensity = 1.0 - jsSmoothstep(0.0, playheadWindow, playheadDist);
            const liveEQHeight = eqIntensity * liveAudioLevels[track] * 20.0;

            // 4. Decay pop animation
            barState.pop = Math.max(0, barState.pop - delta * 50.0);

            const finalHeight = Math.max(sequencerBaseHeight, liveEQHeight, barState.pop, 0.1);

            dummy.scale.set(1, finalHeight, 1);
            dummy.position.set(xPos, -10 + finalHeight / 2, zPos);
            dummy.updateMatrix();
            meshRef.current.setMatrixAt(i, dummy.matrix);
        }
        meshRef.current.instanceMatrix.needsUpdate = true;
    });

    const handleClick = useCallback((e: MouseEvent) => {
        const rect = gl.domElement.getBoundingClientRect();
        const mouse = new THREE.Vector2(
            ((e.clientX - rect.left) / rect.width) * 2 - 1,
            -((e.clientY - rect.top) / rect.height) * 2 + 1
        );

        raycaster.setFromCamera(mouse, camera);

        // To interact with the scrolling bars, we check against a static plane
        // and calculate the track/step from the intersection UV.
        const plane = new THREE.Plane(new THREE.Vector3(0, 1, 0), 10);
        const intersectPoint = new THREE.Vector3();
        if (raycaster.ray.intersectPlane(plane, intersectPoint)) {
             const x = intersectPoint.x;
             const z = intersectPoint.z;

             const u = (x / CONVEYOR_WIDTH) + 0.5;
             const v = (z / CONVEYOR_LENGTH) + 0.5;

             const scrolledV = (v + scrollOffsetRef.current + 1.0) % 1.0;

             const track = Math.floor(u * NUM_TRACKS);
             const step = Math.floor(scrolledV * NUM_STEPS);

             if (track >= 0 && track < NUM_TRACKS && step >=0 && step < NUM_STEPS) {
                const currentGrid = gridRef.current;
                const newGrid = currentGrid.map(t => [...t]);
                const newActiveState = !newGrid[track][step];
                newGrid[track][step] = newActiveState;
                setGrid(newGrid);

                padHitSound.triggerAttackRelease(newActiveState ? "C5" : "A4", "8n", Tone.now());
                const instanceId = step * NUM_TRACKS + track;
                if(barStates[instanceId]) barStates[instanceId].pop = 10.0;
             }
        }
    }, [gl, camera, setGrid, barStates, raycaster, padHitSound]);

    useEffect(() => {
        const canvas = gl.domElement;
        canvas.addEventListener('click', handleClick);
        return () => canvas.removeEventListener('click', handleClick);
    }, [gl, handleClick]);

    const segmentWidth = CONVEYOR_WIDTH / NUM_TRACKS;
    const segmentLength = CONVEYOR_LENGTH / NUM_STEPS;

    return (
        <instancedMesh
            ref={meshRef}
            args={[new THREE.BoxGeometry(segmentWidth * 0.8, 1, segmentLength * 0.8), undefined, NUM_STEPS * NUM_TRACKS]}
        >
            <meshStandardMaterial vertexColors transparent opacity={0.9} />
        </instancedMesh>
    );
};

export default EQBars;
